interface Aura {
  StaticResourceMap: AuraStaticResourceMap;
  initConfig: AuraInitConfig;
  $ServiceApi$: any;
}

interface AuraInitConfig {
  deftype: string;
  token: string;
  pathPrefix: string;
}

interface AuraStaticResourceMap {
  [key: string]: any;
}

declare global {
  interface Window {
    Aura: Aura;
    frameHelperAttached: boolean;
  }
}

export class App {
  parentWindow: Window = window.parent;
  parentDocument: HTMLDocument;
  parentBody: HTMLElement;
  aura: Aura;
  $A: any;
  staticResourceMap: AuraStaticResourceMap;
  appStaticUrl: string;
  constructor() {}

  start() {
    if (this.isAlreadyAttached) {
      return;
    }
    this.isAlreadyAttached = true;
    this.initProps();
    this.appendScripts();
  }
  get isAlreadyAttached(): boolean {
    return this.parentWindow.frameHelperAttached;
  }

  set isAlreadyAttached(val: boolean) {
    this.parentWindow.frameHelperAttached = val;
  }

  private initProps() {
    this.parentDocument = this.parentWindow.document;
    this.parentBody = this.parentDocument.body;
    this.aura = this.parentWindow['Aura'];
    this.$A = this.parentWindow['$A'];
    this.staticResourceMap = this.aura.StaticResourceMap;
    this.configAppStaticResourceUrl();
  }

  private configAppStaticResourceUrl() {
    const appStaticHash = this.staticResourceMap.app[''];
    const pathPrefix = this.$A.getContext().getPathPrefix();
    this.appStaticUrl = `${pathPrefix}/resource/${appStaticHash}/app`;
  }

  private appendScripts() {
    const scripts = ['/js/injection-helper.bundle.js'];
    scripts.forEach(src => this.injectScript(`${this.appStaticUrl}${src}`));
  }

  private injectScript(src: string) {
    console.log('inject script', src);
    const script = document.createElement('script');
    script.src = src;
    this.parentBody.appendChild(script);
  }
}
